What is the running time of the following pseudo code in Big-Oh notation:

cpp
int YYY(int n)
{
    if(n < 10)
        cout << "small";
    else
        for (int i = 0; i < n/2; ++i)
        {
            cout << "ok";
        }
    return n;
}

void main()
{
    for (int i = 0; i < n; ++i)
        a = YYY(i);
}
